int dis[N];   // 源点到各点的最短距离
bool vis[N];  // 是否已确定最短距离

void dijkstra(int src) {
    memset(dist, 0x3f, sizeof dist);
    memset(vis, 0, sizeof vis);
    dis[src] = 0;

    for (int i = 0; i < V; i++) {          // 循环 V 次
        // 1. 在未确定点中找距离最小的点 u
        int u = -1;
        for (int j = 0; j < V; j++) {
            if (!vis[j] && (u == -1 || dis[j] < dis[u]))
                u = j;
        }

        if (dis[u] == INF) break; // 剩余点不可达
        vis[u] = true;

        // 2. 用 u 松弛所有邻接点 v
        for (int v = 0; v < V; v++) {
            if (!vis[v] && dist[u] + w[u][v] < dist[v])
                dist[v] = dist[u] + w[u][v];
        }
    }
}
